SELECT video_path, video_size, upload_date
FROM car_videos
WHERE video_id = 0 AND car_id = 1;

SELECT drive_train_type
FROM drive_trains
WHERE drive_train_all_wheel_drive = 1;

SELECT COUNT(*) AS number_of_versions
FROM car_versions
WHERE car_id = 1;

SELECT make_name
FROM makes
WHERE make_foundation_year = (SELECT MIN(make_foundation_year) FROM makes);
